function validPortMapping(portMapping) {
  let exposedPort = portMapping.split(':')[0];
  let publishedPort = portMapping.split(':')[1];
  return (exposedPort >= 1 && exposedPort <= 65535) && (publishedPort >= 1 && publishedPort <= 65535) && (publishedPort >= exposedPort);
}

