class Solution:
  def valid_port_mapping(self, port_mapping: str) -> bool:
    exposed_port, published_port = port_mapping.split(':')
    return (1 <= int(exposed_port) <= 65535) and (1 <= int(published_port) <= 65535) and (int(published_port) >= int(exposed_port))
